uiBuilder.db.waitLoad().then(() => {
    for (const menu of adminMenus) {
        uiBuilder.addInternalUI(menu);
    }
});

uiManager.addUI(
    "add_icon_override",
    "a",
    (
        player,
        uiID,
        buttonIndex,
        overrideIndex = -1,
        iconID = "",
        overrideCondition = "",
        overrideText = "",
        overrideSubtext = ""
    ) => {
        let ui = uiBuilder.db.getByID(uiID);
        let button = ui.data.buttons[buttonIndex];
        if (overrideIndex > -1 && !iconID && !overrideCondition) {
            iconID = button.iconOverrides[overrideIndex].iconID;
            overrideCondition = button.iconOverrides[overrideIndex].condition;
        }
        let form = new ActionForm();
        form.button(`§7Back`, null, (player) => {
            uiManager.open(player, "edit_icon_overrides", uiID, buttonIndex);
        });
        form.button(
            `§dSet Icon\n§7Sets an icon`,
            icons$1.resolve(iconID),
            (player) => {
                uiManager.open(
                    player,
                    versionData.uiNames.IconViewer,
                    0,
                    (player, iconID2) => {
                        if (iconID2 != null) iconID = iconID2;
                        uiManager.open(
                            player,
                            "add_icon_override",
                            uiID,
                            buttonIndex,
                            overrideIndex,
                            iconID,
                            overrideCondition
                        );
                    }
                );
            }
        );
        form.button(`§bSet Condition\n§7Set a required tag`, null, (player) => {
            let modal = new ModalForm();
            modal.textField(
                "Condition",
                "Write a condition, usually a tag",
                overrideCondition
            );
            modal.show(player, false, (player, response) => {
                if (response.canceled)
                    return uiManager.open(
                        player,
                        "add_icon_override",
                        uiID,
                        buttonIndex,
                        overrideIndex,
                        iconID,
                        overrideCondition
                    );

                overrideCondition = response.formValues[0];

                return uiManager.open(
                    player,
                    "add_icon_override",
                    uiID,
                    buttonIndex,
                    overrideIndex,
                    iconID,
                    overrideCondition
                );
            });
        });
        if (iconID && overrideCondition) {
            form.button(
                `§a${
                    overrideIndex == -1 ? "Create" : "Edit"
                }\n§7Create the override`,
                null,
                (player) => {
                    uiBuilder.addIconOverride(
                        uiID,
                        button.id,
                        iconID,
                        overrideCondition,
                        overrideIndex
                    );
                    uiManager.open(
                        player,
                        "edit_icon_overrides",
                        uiID,
                        buttonIndex
                    );
                }
            );
        }
        form.show(player, false, () => {});
    }
);

uiManager.addUI(
    "edit_icon_override",
    "a",
    (player, uiID, buttonIndex, overrideIndex) => {
        let ui = uiBuilder.db.getByID(uiID);
        let button = ui.data.buttons[buttonIndex];
        let form = new ActionForm();
        form.button(`§7Back`, null, (player) => {
            uiManager.open(player, "edit_icon_overrides", uiID, buttonIndex);
        });
        form.button(`§eEdit\n§7Edit the override`, null, (player) => {
            uiManager.open(
                player,
                "add_icon_override",
                uiID,
                buttonIndex,
                overrideIndex
            );
        });
        form.button(`§bMove Up`, `textures/azalea_icons/Up`, (player) => {
            array_move(
                button.iconOverrides,
                overrideIndex,
                overrideIndex - 1 < 0 ? overrideIndex : overrideIndex - 1
            );
            uiBuilder.db.overwriteDataByID(ui.id, ui.data);
            uiManager.open(player, "edit_icon_overrides", uiID, buttonIndex);
        });
        form.button(`§bMove Down`, `textures/azalea_icons/Down`, (player) => {
            array_move(
                button.iconOverrides,
                overrideIndex,
                overrideIndex + 1 >= button.iconOverrides.length
                    ? overrideIndex
                    : overrideIndex + 1
            );
            uiBuilder.db.overwriteDataByID(ui.id, ui.data);
            uiManager.open(player, "edit_icon_overrides", uiID, buttonIndex);
        });
        form.button(`§cDelete\n§7Delete the override`, null, (player) => {
            button.iconOverrides.splice(overrideIndex, 1);
            uiBuilder.db.overwriteDataByID(ui.id, ui.data);
            uiManager.open(player, "edit_icon_overrides", uiID, buttonIndex);
        });
        form.show(player, false, (player, response) => {});
    }
);

uiManager.addUI("edit_icon_overrides", "yes", (player, id, buttonIndex) => {
    let doc = uiBuilder.db.getByID(id);
    let button = doc.data.buttons[buttonIndex];
    let form = new ActionForm();
    form.button(`§7Back`, null, (player) => {
        uiManager.open(
            player,
            versionData.uiNames.UIBuilderEditButton,
            id,
            buttonIndex
        );
    });
    form.button(`§aAdd new override\n§7Adds new override`, null, (player) => {
        uiManager.open(player, "add_icon_override", id, buttonIndex);
    });
    for (let i = 0; i < button.iconOverrides.length; i++) {
        let override = button.iconOverrides[i];
        form.button(
            `§a${override.iconID}\n§r§7${override.condition}`,
            icons$1.resolve(override.iconID),
            (player) => {
                uiManager.open(
                    player,
                    "edit_icon_override",
                    id,
                    buttonIndex,
                    i
                );
            }
        );
    }
    form.show(player, false, (player, response) => {});
});

class ScripteventManager {
    constructor() {
        this.scriptevents = {};

        system.afterEvents.scriptEventReceive.subscribe((e) => {
            if (this.scriptevents[e.id]) {
                this.scriptevents[e.id]({ source: "command", event: e });
            }
        });
    }
    register(identifier, fn) {
        this.scriptevents[identifier] = fn;
    }
    unregister(identifier) {
        try {
            delete this.scriptevents[identifier];
        } catch {}
    }
}

var ScriptEventManager = new ScripteventManager();

function normalizePercentages(arr) {
    const total = arr.reduce((sum, val) => sum + val, 0);
    if (total === 0) return arr.map(() => 0); // avoid div by zero
    return arr.map((val) => (val / total) * 100);
}

function weightedRandomIndex(percentages) {
    const total = percentages.reduce((sum, val) => sum + val, 0);
    const rand = Math.random() * total;
    let cumulative = 0;

    for (let i = 0; i < percentages.length; i++) {
        cumulative += percentages[i];
        if (rand < cumulative) return i;
    }
    return percentages.length - 1; // fallback just in case
}

ScriptEventManager.register("leaf:switch_sidebar", ({ event }) => {
    if (event.sourceType != ScriptEventSource.Entity) return;
    for (const tag of event.sourceEntity.getTags()) {
        if (!tag.startsWith("sidebar:")) continue;
        event.sourceEntity.removeTag(tag);
    }
    if (event.message != "default")
        event.sourceEntity.addTag(`sidebar:${event.message}`);
});

