uiManager.addUI(
    versionData.uiNames.Clans.Create,
    "Create a clan",
    (player, defaultValue = null, error = null) => {
        if (!configAPI.getProperty("Clans"))
            return player.sendMessage("Clans are not enabled");
        if (configAPI.getProperty("clans:enable_pay_to_create")) {
            let amount = prismarineDb.economy.getMoney(
                player,
                configAPI.getProperty("clans:clan_price_currency")
            );
            let currency = configAPI.getProperty("clans:clan_price_currency");
            let requiredAmount = configAPI.getProperty("clans:clan_price");
            if (amount < configAPI.getProperty("clans:clan_price")) {
                let actionForm = new ActionForm();
                actionForm.title("Error");
                actionForm.body(
                    `You dont have enough money to create a clan. You require §e${
                        prismarineDb.economy.getCurrency(currency).symbol
                    } ${requiredAmount}`
                );
                actionForm.button(
                    `§cBack\n§7Go back to main clans page`,
                    `textures/blocks/barrier`,
                    (player) => {
                        uiManager.open(player, versionData.uiNames.Clans.Root);
                    }
                );
                actionForm.show(player, false, (player, response) => {});
                return;
            }
        }
        let modal = new ModalForm();
        modal.textField(
            `${error ? `§c${error}\n\n` : ``}Name (a-z A-Z 0-9)`,
            "leaf"
        );
        modal.show(player, false, (player, response) => {
            prismarineDb.economy.getMoney(
                player,
                configAPI.getProperty("clans:clan_price_currency")
            );
            let currency = configAPI.getProperty("clans:clan_price_currency");
            let requiredAmount = configAPI.getProperty("clans:clan_price");
            if (response.canceled) return;
            try {
                let clan = OpenClanAPI$1.createClan(
                    player,
                    response.formValues[0]
                );
                uiManager.open(player, versionData.uiNames.Clans.Root);
                prismarineDb.economy.removeMoney(
                    player,
                    requiredAmount,
                    currency
                );
            } catch (e) {
                uiManager.open(
                    player,
                    versionData.uiNames.Clans.Create,
                    response.formValues[0],
                    e
                );
            }
        });
    }
);

