// PRISMARINEDB HAS A PERMISSIONS SYSTEM WHY IS THIS HERE

class Permissions {
    constructor() {
        this.db = prismarineDb.table("Permissions");
        this.#initializeAdmin();
        this.#initializeDefault();
    }
    #initializeAdmin() {
        let doc = this.db.findFirst({
            tag: "admin",
        });
        if (!doc) {
            this.db.insertDocument({
                isAdmin: true,
                permissions: [],
                isDefault: false,
                isCustom: false,
                isDeletable: false,
                isEditable: false,
                tag: "admin",
            });
        }
    }
    #initializeDefault() {
        let doc = this.db.findFirst({
            tag: "default",
        });
        if (!doc) {
            this.db.insertDocument({
                isAdmin: false,
                permissions: [],
                isDefault: true,
                isCustom: false,
                isDeletable: false,
                isEditable: true,
                tag: "default",
            });
        }
    }
    hasPermission(player, permission) {
        let perms = [];
        for (const role of this.db.findDocuments(null)) {
            if (player.hasTag(role.data.tag)) {
                if (role.data.isAdmin) return true;
                perms = [...perms, ...role.data.permissions];
            }
        }
        return perms.includes(permission);
    }
    createRole(tag) {
        if (this.db.findFirst({ tag })) return;
        this.db.insertDocument({
            tag,
            isAdmin: false,
            permissions: [],
            isDefault: false,
            isCustom: true,
            isDeletable: true,
            isEditable: true,
        });
    }
    editRolePermissions(id, permissions = [], isAdmin = false) {
        if (isAdmin) {
            let doc = this.db.getByID(id);
            if (!doc) return;
            doc.data.isAdmin = true;
            this.db.overwriteDataByID(doc.id, doc.data);
            return;
        }
        let doc = this.db.getByID(id);
        if (!doc) return;
        doc.data.isAdmin = false;
        doc.data.permissions = permissions;
        this.db.overwriteDataByID(doc.id, doc.data);
    }
}

var permissionsSystem = new Permissions();

let cfgDb = combatLogDB;
function getSeconds() {
    return parseInt(
        cfgDb.get("CombatlogSeconds") ? cfgDb.get("CombatlogSeconds") : 10
    );
}
function getIsEnabled() {
    return cfgDb.get("CombatlogEnabled") ? true : false;
}
CommandManager$1.addCommand(
    "combatlog",
    { description: "yes", author: "TrashyKitty", category: "Admin" },
    ({ msg, args }) => {
        msg.sender.sendCommand(
            "Use !combatlog toggle to toggle and !combatlog set-seconds to set seconds"
        );
    }
);
CommandManager$1.addSubcommand(
    "combatlog",
    "toggle",
    { description: "toggle combat log" },
    ({ msg, args }) => {
        if (!permissionsSystem.hasPermission(msg.sender, "combatlog.edit"))
            return msg.sender.sendMessage("§cyou no no have permission");
        let currentValue = getIsEnabled();
        cfgDb.set("CombatlogEnabled", !currentValue);

        if (currentValue) {
            msg.sender.sendMessage("§cDisabled");
        } else msg.sender.sendMessage("§aEnabled");
    }
);
CommandManager$1.addSubcommand(
    "combatlog",
    "set-seconds",
    { description: "toggle combat log" },
    ({ msg, args }) => {
        if (!permissionsSystem.hasPermission(msg.sender, "combatlog.edit"))
            return msg.sender.sendMessage("§cyou no no have permission");
        let currentValue = getSeconds();
        if (args.length) {
            if (!/^\d+$/.test(args[0]))
                return msg.sender.sendMessage(
                    "§cFirst argument needs to be a number"
                );
            cfgDb.set("CombatlogSeconds", parseInt(args[0]));
            return msg.sender.sendMessage(
                `§aSet seconds to §f${parseInt(args[0])}`
            );
        } else {
            return msg.sender.sendMessage(
                `§cYou need a number amount: §f${currentValue}`
            );
        }
    }
);
